#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char S[N + 1];
        scanf("%s", S);
        int power = 0;
        for (int i = 0; i < N - K; i++) {
            int changes = 0;
            for (int j = 0; j < K; j++) {
                if (S[i + j] != S[i + j + 1]) {
                    changes++;
                }
            }
            power += changes;
        }
        printf("%d\n", power);
    }
    return 0;
}

