code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String S = sc.next();
            int power = 0;
            for (int i = 0; i < N - K; i++) {
                int changes = 0;
                for (int j = 0; j < K; j++) {
                    if (S.charAt(i + j) != S.charAt(i + j + 1)) {
                        changes++;
                    }
                }
                power += changes;
            }
            System.out.println(power);
        }
    }
}

