    const [N, K] = readline().split(' ').map(Number);
    const S = readline().trim();
    let power = 0;
    for (let j = 0; j < N - K; j++) {
        let changes = 0;
        for (let k = 0; k < K; k++) {
            if (S[j + k] !== S[j + k + 1]) {
                changes++;
            }
        }
        power += changes;
    }
    console.log(power);
}

